        [Test]
        public void Equality_MatchesBranchAndValue()
        {
            var shared = new Branch0("shared");
            var left = new OneOf<Branch0, Branch1, Branch2, Branch3, Branch4, Branch5, Branch6>(shared);
            var same = new OneOf<Branch0, Branch1, Branch2, Branch3, Branch4, Branch5, Branch6>(shared);
            var otherValue = new OneOf<Branch0, Branch1, Branch2, Branch3, Branch4, Branch5, Branch6>(new Branch0("other"));
            var otherBranch = new OneOf<Branch0, Branch1, Branch2, Branch3, Branch4, Branch5, Branch6>(new Branch1("shared"));

            Assert.That(left.Equals(same), Is.True);
            Assert.That(left.Equals((object)same), Is.True);
            Assert.That(left == same, Is.True);
            Assert.That(left != same, Is.False);
            Assert.That(left.Equals(otherValue), Is.False);
            Assert.That(left.Equals(otherBranch), Is.False);
        }

        [Test]
        public void GetHashCode_ForEqualValues_IsSame()
        {
            var shared = new Branch0("shared");
            var left = new OneOf<Branch0, Branch1, Branch2, Branch3, Branch4, Branch5, Branch6>(shared);
            var right = new OneOf<Branch0, Branch1, Branch2, Branch3, Branch4, Branch5, Branch6>(shared);

            Assert.That(left.GetHashCode(), Is.EqualTo(right.GetHashCode()));
        }
